"""
Fixed additional test for the dict with numpy arrays matches fix.
"""

import pytest
import numpy as np
from bokeh.core.property.bases import Property

def test_property_matches_dict_with_numpy_arrays():
    """Test that matches properly handles dictionaries containing numpy arrays."""
    p = Property()

    # Test identical dictionaries with numpy arrays
    dict_np1 = {'a': np.array([1, 2, 3]), 'b': np.array([4, 5, 6])}
    dict_np2 = {'a': np.array([1, 2, 3]), 'b': np.array([4, 5, 6])}
    assert p.matches(dict_np1, dict_np2) is True

    # Test different dictionaries with numpy arrays (different values)
    dict_np3 = {'a': np.array([1, 2, 3]), 'b': np.array([4, 5, 7])}
    assert p.matches(dict_np1, dict_np3) is False

    # Test different dictionaries with numpy arrays (different keys)
    dict_np4 = {'a': np.array([1, 2, 3]), 'c': np.array([4, 5, 6])}
    assert p.matches(dict_np1, dict_np4) is False

    # Test different sized arrays
    dict_np5 = {'a': np.array([1, 2]), 'b': np.array([4, 5])}
    assert p.matches(dict_np1, dict_np5) is False

def test_property_matches_dict_with_mixed_types():
    """Test that matches handles dictionaries with mixed types including numpy arrays."""
    p = Property()

    # Mix of numpy arrays, lists, and scalars
    dict_mixed1 = {
        'array': np.array([1, 2, 3]),
        'list': [4, 5, 6],
        'scalar': 42,
        'string': 'hello'
    }
    dict_mixed2 = {
        'array': np.array([1, 2, 3]),
        'list': [4, 5, 6],
        'scalar': 42,
        'string': 'hello'
    }
    dict_mixed3 = {
        'array': np.array([1, 2, 3]),
        'list': [4, 5, 6],
        'scalar': 43,  # Different scalar
        'string': 'hello'
    }

    assert p.matches(dict_mixed1, dict_mixed2) is True
    assert p.matches(dict_mixed1, dict_mixed3) is False

def test_property_matches_problematic_case():
    """Test the specific case that was causing the original issue."""
    p = Property()

    # This is the exact case from the issue - non-empty arrays that cause ValueError
    dict_np1 = {'a': np.array([1, 2, 3]), 'b': np.array([4, 5, 6])}
    dict_np2 = {'a': np.array([1, 2, 3]), 'b': np.array([4, 5, 6])}
    dict_np3 = {'a': np.array([1, 2, 3]), 'b': np.array([4, 5, 7])}

    # These should not raise ValueError and should give correct results
    assert p.matches(dict_np1, dict_np2) is True   # Same content
    assert p.matches(dict_np1, dict_np3) is False  # Different content

if __name__ == "__main__":
    test_property_matches_dict_with_numpy_arrays()
    test_property_matches_dict_with_mixed_types()
    test_property_matches_problematic_case()
    print("All additional tests passed!")

