"""
Boundary condition tests for the fix.
"""

import numpy as np
from bokeh.core.property.bases import Property

def test_boundary_conditions():
    """Test various boundary conditions."""
    p = Property()

    print("Testing boundary conditions...")

    # Test None values
    assert p.matches(None, None) is True
    assert p.matches(None, {}) is False
    assert p.matches({}, None) is False
    print("✅ None value handling correct")

    # Test nested dictionaries
    nested1 = {
        'level1': {
            'level2': np.array([1, 2, 3]),
            'regular': 'value'
        },
        'array': np.array([4, 5, 6])
    }
    nested2 = {
        'level1': {
            'level2': np.array([1, 2, 3]),
            'regular': 'value'
        },
        'array': np.array([4, 5, 6])
    }
    nested3 = {
        'level1': {
            'level2': np.array([1, 2, 4]),  # Different
            'regular': 'value'
        },
        'array': np.array([4, 5, 6])
    }

    assert p.matches(nested1, nested2) is True
    assert p.matches(nested1, nested3) is False
    print("✅ Nested dictionary handling correct")

    # Test lists with arrays (should still raise if not handled)
    try:
        list1 = [np.array([1, 2, 3])]
        list2 = [np.array([1, 2, 3])]
        result = p.matches(list1, list2)
        print(f"✅ Lists with arrays handled: {result}")
    except ValueError:
        print("ℹ️ Lists with arrays still raise ValueError (expected)")

    print("All boundary conditions tested successfully!")

if __name__ == "__main__":
    test_boundary_conditions()

